// create a d path using the addCircularPathData
//reference code : https://bl.ocks.org/tomshanley/b82d9aede85694b1422786ef41536ec5
export function sankeyCircularLink(link) {
    let pathString = '';
    let pathData = {};

    if (link.circularLinkType == 'top') {
        pathString =
            // start at the right of the source node
            `M${link.circularPathData.sourceX} ${link.circularPathData.sourceY} ` +
            // line right to buffer point
            `L${link.circularPathData.leftInnerExtent} ${link.circularPathData.sourceY} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.leftLargeArcRadius} ${link.circularPathData.leftSmallArcRadius} 0 0 0 ${
                // End of arc X //End of arc Y
                link.circularPathData.leftFullExtent
            } ${link.circularPathData.sourceY - link.circularPathData.leftSmallArcRadius} ` + // End of arc X
            // line up to buffer point
            `L${link.circularPathData.leftFullExtent} ${link.circularPathData.verticalLeftInnerExtent} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.leftLargeArcRadius} ${link.circularPathData.leftLargeArcRadius} 0 0 0 ${
                // End of arc X //End of arc Y
                link.circularPathData.leftInnerExtent
            } ${link.circularPathData.verticalFullExtent} ` + // End of arc X
            // line left to buffer point
            `L${link.circularPathData.rightInnerExtent} ${link.circularPathData.verticalFullExtent} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.rightLargeArcRadius} ${link.circularPathData.rightLargeArcRadius} 0 0 0 ${
                // End of arc X //End of arc Y
                link.circularPathData.rightFullExtent
            } ${link.circularPathData.verticalRightInnerExtent} ` + // End of arc X
            // line down
            `L${link.circularPathData.rightFullExtent} ${link.circularPathData.targetY - link.circularPathData.rightSmallArcRadius} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.rightLargeArcRadius} ${link.circularPathData.rightSmallArcRadius} 0 0 0 ${
                // End of arc X //End of arc Y
                link.circularPathData.rightInnerExtent
            } ${link.circularPathData.targetY} ` + // End of arc X
            // line to end
            `L${link.circularPathData.targetX} ${
                link.circularPathData.targetY

                //RT
            } ` +
            `L${link.circularPathData.targetX} ${link.circularPathData.targetY - link.width} ` + // line right to buffer point
            `L${link.circularPathData.rightInnerExtent1} ${link.circularPathData.targetY - link.width} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.rightLargeArcRadius1} ${link.circularPathData.rightSmallArcRadius1} 0 0 1 ${
                // End of arc X //End of arc Y
                link.circularPathData.rightFullExtent1
            } ${link.circularPathData.targetY - link.width - link.circularPathData.rightSmallArcRadius1} ` + // End of arc X
            // line up to buffer point
            `L${link.circularPathData.rightFullExtent1} ${link.circularPathData.verticalRightInnerExtent1 +
                link.circularPathData.rightLargeArcRadius1} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.rightLargeArcRadius1} ${link.circularPathData.rightLargeArcRadius1} 0 0 1 ${
                // End of arc X //End of arc Y
                link.circularPathData.rightInnerExtent1
            } ${link.circularPathData.verticalFullExtent1} ` + // End of arc X
            // line left to buffer point
            `L${link.circularPathData.leftInnerExtent1} ${link.circularPathData.verticalFullExtent1} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.leftLargeArcRadius1} ${link.circularPathData.leftLargeArcRadius1} 0 0 1 ${
                // End of arc X //End of arc Y
                link.circularPathData.leftFullExtent1
            } ${link.circularPathData.verticalLeftInnerExtent1 + link.circularPathData.leftLargeArcRadius1} ` + // End of arc X
            // line down
            `L${link.circularPathData.leftFullExtent1} ${link.circularPathData.sourceY -
                link.width -
                link.circularPathData.leftSmallArcRadius1} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.leftLargeArcRadius1} ${link.circularPathData.leftSmallArcRadius1} 0 0 1 ${
                // End of arc X //End of arc Y
                link.circularPathData.leftInnerExtent1
            } ${link.circularPathData.sourceY - link.width} ` + // End of arc X
            // line to end
            `L${link.circularPathData.sourceX} ${link.circularPathData.sourceY - link.width}`;
    } else {
        // bottom path
        pathString =
            // start at the right of the source node
            `M${link.circularPathData.sourceX} ${link.circularPathData.sourceY} ` +
            // line right to buffer point
            `L${link.circularPathData.leftInnerExtent} ${link.circularPathData.sourceY} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.leftLargeArcRadius} ${link.circularPathData.leftSmallArcRadius} 0 0 1 ${
                // End of arc X //End of arc Y
                link.circularPathData.leftFullExtent
            } ${link.circularPathData.sourceY + link.circularPathData.leftSmallArcRadius} ` + // End of arc X
            // line down to buffer point
            `L${link.circularPathData.leftFullExtent} ${link.circularPathData.verticalLeftInnerExtent} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.leftLargeArcRadius} ${link.circularPathData.leftLargeArcRadius} 0 0 1 ${
                // End of arc X //End of arc Y
                link.circularPathData.leftInnerExtent
            } ${link.circularPathData.verticalFullExtent} ` + // End of arc X
            // line left to buffer point
            `L${link.circularPathData.rightInnerExtent} ${link.circularPathData.verticalFullExtent} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.rightLargeArcRadius} ${link.circularPathData.rightLargeArcRadius} 0 0 1 ${
                // End of arc X //End of arc Y
                link.circularPathData.rightFullExtent
            } ${link.circularPathData.verticalRightInnerExtent} ` + // End of arc X
            // line up
            `L${link.circularPathData.rightFullExtent} ${link.circularPathData.targetY + link.circularPathData.rightSmallArcRadius} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.rightLargeArcRadius} ${link.circularPathData.rightSmallArcRadius} 0 0 1 ${
                // End of arc X //End of arc Y
                link.circularPathData.rightInnerExtent
            } ${link.circularPathData.targetY} ` + // End of arc X
            // line to end
            `L${link.circularPathData.targetX} ${link.circularPathData.targetY} ` +
            //RT
            `L${link.circularPathData.targetX} ${link.circularPathData.targetY + link.width} ` +
            `L${link.circularPathData.rightInnerExtent1} ${link.circularPathData.targetY + link.width} ` +
            `A${link.circularPathData.rightLargeArcRadius1} ${link.circularPathData.rightSmallArcRadius1} 0 0 0 ${
                // End of arc X //End of arc Y
                link.circularPathData.rightFullExtent1
            } ${link.circularPathData.targetY + link.width + link.circularPathData.rightSmallArcRadius1} ` + // End of arc X
            //
            `L${link.circularPathData.rightFullExtent1} ${
                link.circularPathData.verticalRightInnerExtent1 - link.circularPathData.rightLargeArcRadius1
                // line down to buffer point
                //
                //     // Arc around: Centre of arc X and  //Centre of arc Y
            } ` +
            `A${link.circularPathData.rightLargeArcRadius1} ${link.circularPathData.rightLargeArcRadius1} 0 0 0 ${
                // End of arc X //End of arc Y
                link.circularPathData.rightInnerExtent1
            } ${
                link.circularPathData.verticalFullExtent1
                // End of arc X
                //     // line left to buffer point
            } ` +
            `L${link.circularPathData.leftInnerExtent1} ${link.circularPathData.verticalFullExtent1} ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.leftLargeArcRadius1} ${link.circularPathData.leftLargeArcRadius1} 0 0 0 ${
                // End of arc X //End of arc Y
                link.circularPathData.leftFullExtent1
            } ${link.circularPathData.verticalLeftInnerExtent1 - link.circularPathData.leftLargeArcRadius1} ` + // End of arc X
            // line up
            `L${link.circularPathData.leftFullExtent1} ${
                link.circularPathData.sourceY + link.width + link.circularPathData.leftSmallArcRadius1
                //
            } ` +
            // Arc around: Centre of arc X and  //Centre of arc Y
            `A${link.circularPathData.leftLargeArcRadius1} ${link.circularPathData.leftSmallArcRadius1} 0 0 0 ${
                // End of arc X //End of arc Y
                link.circularPathData.leftInnerExtent1
            } ${link.circularPathData.sourceY + link.width} ` + // End of arc X
            // line to end
            `L${link.circularPathData.sourceX} ${link.circularPathData.sourceY + link.width}`;
    }

    return pathString;
}
